cpdef uint64_t calc_min_two(const uint64_t a, const uint64_t b) nogil:
    if a <= b:
        return a
    else:
        return b

cpdef uint64_t calc_min_three(const uint64_t a, const uint64_t b, const uint64_t c) nogil:
    cdef uint64_t the_min = calc_min_two(a, b)

